INSERT INTO paa.lookup_finding (case_id, category, tool_name, status_badge, title, raw_findings, inference_text, source_label, confidence_pct) VALUES
  ('REQ-2026-2000', 'market_price', 'market_price_lookup', 'da_xac_thuc', 'Giá thị trường', ARRAY['7 giao dịch so sánh trong bán kính 1.1km.'], 'Giá giao dịch so sánh dao động 122.7–162.1 triệu/m², trung vị khoảng 152.0 triệu/m². Giá tương đối ổn định qua các giao dịch gần đây, chưa thấy biến động bất thường. Nên ưu tiên trọng số cao hơn cho các giao dịch gần đây khi đưa vào bước định giá.', 'market_price_lookup', 78),
  ('REQ-2026-2000', 'planning_zoning', 'planning_zoning_lookup', 'da_xac_thuc', 'Quy hoạch', ARRAY['Không nằm trong khu vực quy hoạch treo.','Lộ giới hẻm/đường dự kiến mở rộng lên 8m theo đồ án quy hoạch 1/2000 phê duyệt 2021.','Không thuộc diện giải toả, thu hồi đất.'], 'Không có yếu tố quy hoạch bất lợi, có thể tăng nhẹ giá trị nếu lộ giới được mở rộng trong 2–3 năm tới nhờ cải thiện khả năng tiếp cận.', 'planning_zoning_lookup', 93),
  ('REQ-2026-2000', 'legal_status', 'legal_status_lookup', 'luu_y', 'Pháp lý', ARRAY['Sổ hồng đứng tên chính chủ nhưng có ghi chú thế chấp đã tất toán, chưa xoá đăng ký.','Không ghi nhận tranh chấp tại thời điểm tra cứu.'], 'Cần yêu cầu khách hàng bổ sung văn bản xoá đăng ký thế chấp cũ trước khi hoàn tất hồ sơ.', 'legal_status_lookup', 55),
  ('REQ-2026-2000', 'neighborhood_amenity', 'neighborhood_amenity_lookup', 'da_xac_thuc', 'Tiện ích xung quanh', ARRAY['Trường tiểu học: 220m · Chợ dân sinh: 460m','Trạm xe bus: 352m · Bệnh viện quận: 0.8km'], 'Mật độ tiện ích cao hơn trung bình khu vực — yếu tố hỗ trợ tích cực cho nhu cầu ở thực và thanh khoản khi cần bán lại.', 'neighborhood_amenity_lookup', 81),
  ('REQ-2026-2000', 'environmental_risk', 'environmental_risk_lookup', 'luu_y', 'Môi trường', ARRAY['Ghi nhận ngập nhẹ cục bộ mùa mưa 2022–2023 (mức nước <20cm, rút trong ngày).','Không nằm trong vùng cảnh báo sạt lở, ô nhiễm công nghiệp.'], 'Rủi ro ngập ở mức thấp, không ảnh hưởng đáng kể đến giá trị định giá, nhưng nên khuyến nghị khách hàng mua bảo hiểm tài sản.', 'environmental_risk_lookup', 57),
  ('REQ-2026-2000', 'liquidity_stat', 'liquidity_stat_lookup', 'da_xac_thuc', 'Thanh khoản khu vực', ARRAY['Thời gian bán trung bình: 37 ngày · Tỷ lệ giao dịch thành công: 87%','Số tin rao bán cùng phân khúc trong bán kính 1km: 17 tin'], 'Thanh khoản khá tốt so với mặt bằng chung phân khúc — hỗ trợ tích cực cho khả năng xử lý tài sản bảo đảm khi cần thiết.', 'liquidity_stat_lookup', 94),
  ('REQ-2026-2000', 'stigma_reputation', 'stigma_reputation_lookup', 'da_xac_thuc', 'Dư luận / tâm linh', ARRAY['Không ghi nhận tin đồn hay sự việc bất thường liên quan tài sản/khu vực.','Không có bài báo, hồ sơ công an hoặc dữ liệu tiêu cực liên quan.'], 'Không phát hiện yếu tố bất lợi về dư luận/tâm linh — không ảnh hưởng đến giá trị hay thanh khoản.', 'stigma_reputation_lookup', 97),
  ('REQ-2026-2001', 'market_price', 'market_price_lookup', 'da_xac_thuc', 'Giá thị trường', ARRAY['5 giao dịch so sánh trong bán kính 1.3km.'], 'Giá giao dịch so sánh dao động 173.9–217.6 triệu/m², trung vị khoảng 188.4 triệu/m². Xu hướng tăng theo thời gian, giao dịch gần nhất cao hơn đáng kể so với giao dịch xa nhất, cho thấy khu vực đang trong đà tăng giá. Nên ưu tiên trọng số cao hơn cho các giao dịch gần đây khi đưa vào bước định giá.', 'market_price_lookup', 87),
  ('REQ-2026-2001', 'planning_zoning', 'planning_zoning_lookup', 'luu_y', 'Quy hoạch', ARRAY['Một phần thửa đất (4m²) nằm trong hành lang lộ giới quy hoạch mở rộng đường.','Chưa có quyết định thu hồi đất chính thức tại thời điểm tra cứu.'], 'Cần đối chiếu thêm bản vẽ quy hoạch chi tiết 1/500 để xác định chính xác phần diện tích ảnh hưởng trước khi đưa vào định giá.', 'planning_zoning_lookup', 45),
  ('REQ-2026-2001', 'legal_status', 'legal_status_lookup', 'da_xac_thuc', 'Pháp lý', ARRAY['Sổ hồng đứng tên chính chủ, cấp 16/08/2011.','Không ghi nhận tranh chấp, kê biên hay khiếu nại.','Không đang thế chấp tại tổ chức tín dụng khác.'], 'Tình trạng pháp lý sạch, đủ điều kiện nhận thế chấp. Yếu tố tích cực, giảm đáng kể rủi ro khi xử lý tài sản bảo đảm nếu phát sinh nợ xấu.', 'legal_status_lookup', 92),
  ('REQ-2026-2001', 'neighborhood_amenity', 'neighborhood_amenity_lookup', 'luu_y', 'Tiện ích xung quanh', ARRAY['Trường tiểu học gần nhất: 1537m · Chợ dân sinh: 1388m','Chưa có tuyến xe bus đi qua trong bán kính 1km.'], 'Mật độ tiện ích thấp hơn trung bình khu vực, có thể ảnh hưởng nhẹ đến nhu cầu ở thực so với các vị trí trung tâm hơn.', 'neighborhood_amenity_lookup', 30),
  ('REQ-2026-2001', 'environmental_risk', 'environmental_risk_lookup', 'luu_y', 'Môi trường', ARRAY['Ghi nhận ngập nhẹ cục bộ mùa mưa 2023–2025 (mức nước <15cm, rút trong ngày).','Không nằm trong vùng cảnh báo sạt lở, ô nhiễm công nghiệp.'], 'Rủi ro ngập ở mức thấp, không ảnh hưởng đáng kể đến giá trị định giá, nhưng nên khuyến nghị khách hàng mua bảo hiểm tài sản.', 'environmental_risk_lookup', 57),
  ('REQ-2026-2001', 'liquidity_stat', 'liquidity_stat_lookup', 'da_xac_thuc', 'Thanh khoản khu vực', ARRAY['Thời gian bán trung bình: 48 ngày · Tỷ lệ giao dịch thành công: 92%','Số tin rao bán cùng phân khúc trong bán kính 1km: 18 tin'], 'Thanh khoản khá tốt so với mặt bằng chung phân khúc — hỗ trợ tích cực cho khả năng xử lý tài sản bảo đảm khi cần thiết.', 'liquidity_stat_lookup', 95),
  ('REQ-2026-2001', 'stigma_reputation', 'stigma_reputation_lookup', 'da_xac_thuc', 'Dư luận / tâm linh', ARRAY['Không ghi nhận tin đồn hay sự việc bất thường liên quan tài sản/khu vực.','Không có bài báo, hồ sơ công an hoặc dữ liệu tiêu cực liên quan.'], 'Không phát hiện yếu tố bất lợi về dư luận/tâm linh — không ảnh hưởng đến giá trị hay thanh khoản.', 'stigma_reputation_lookup', 89),
  ('REQ-2026-2002', 'market_price', 'market_price_lookup', 'da_xac_thuc', 'Giá thị trường', ARRAY['6 giao dịch so sánh trong bán kính 1.6km.'], 'Giá giao dịch so sánh dao động 200.3–273.8 triệu/m², trung vị khoảng 256.4 triệu/m². Xu hướng tăng theo thời gian, giao dịch gần nhất cao hơn đáng kể so với giao dịch xa nhất, cho thấy khu vực đang trong đà tăng giá. Nên ưu tiên trọng số cao hơn cho các giao dịch gần đây khi đưa vào bước định giá.', 'market_price_lookup', 85),
