  ('REQ-2026-2029', 'liquidity_stat', 'liquidity_stat_lookup', 'da_xac_thuc', 'Thanh khoản khu vực', ARRAY['Thời gian bán trung bình: 41 ngày · Tỷ lệ giao dịch thành công: 87%','Số tin rao bán cùng phân khúc trong bán kính 1km: 20 tin'], 'Thanh khoản khá tốt so với mặt bằng chung phân khúc — hỗ trợ tích cực cho khả năng xử lý tài sản bảo đảm khi cần thiết.', 'liquidity_stat_lookup', 90),
  ('REQ-2026-2029', 'stigma_reputation', 'stigma_reputation_lookup', 'chua_xac_thuc', 'Dư luận / tâm linh', ARRAY['Ghi nhận tin đồn dân cư chưa xác thực liên quan 1 sự việc năm 2015.','Không có bài báo, hồ sơ công an hoặc dữ liệu chính thức xác nhận.'], 'Độ tin cậy nguồn tin thấp, chưa đủ cơ sở kết luận ảnh hưởng đến giá trị hay thanh khoản. Khuyến nghị thẩm định viên xác minh thực địa trước khi đưa vào báo cáo chính thức.', 'stigma_reputation_lookup', 40),
  ('REQ-2026-2030', 'market_price', 'market_price_lookup', 'da_xac_thuc', 'Giá thị trường', ARRAY['8 giao dịch so sánh trong bán kính 0.9km.'], 'Giá giao dịch so sánh dao động 325.6–448.6 triệu/m², trung vị khoảng 410.1 triệu/m². Xu hướng tăng theo thời gian, giao dịch gần nhất cao hơn đáng kể so với giao dịch xa nhất, cho thấy khu vực đang trong đà tăng giá. Nên ưu tiên trọng số cao hơn cho các giao dịch gần đây khi đưa vào bước định giá.', 'market_price_lookup', 70),
  ('REQ-2026-2030', 'planning_zoning', 'planning_zoning_lookup', 'da_xac_thuc', 'Quy hoạch', ARRAY['Không nằm trong khu vực quy hoạch treo.','Lộ giới hẻm/đường dự kiến giữ nguyên theo đồ án quy hoạch 1/2000 phê duyệt 2023.','Không thuộc diện giải toả, thu hồi đất.'], 'Không có yếu tố quy hoạch bất lợi, có thể tăng nhẹ giá trị nếu lộ giới được mở rộng trong 2–3 năm tới nhờ cải thiện khả năng tiếp cận.', 'planning_zoning_lookup', 83),
  ('REQ-2026-2030', 'legal_status', 'legal_status_lookup', 'da_xac_thuc', 'Pháp lý', ARRAY['Sổ hồng đứng tên chính chủ, cấp 20/05/2010.','Không ghi nhận tranh chấp, kê biên hay khiếu nại.','Không đang thế chấp tại tổ chức tín dụng khác.'], 'Tình trạng pháp lý sạch, đủ điều kiện nhận thế chấp. Yếu tố tích cực, giảm đáng kể rủi ro khi xử lý tài sản bảo đảm nếu phát sinh nợ xấu.', 'legal_status_lookup', 97),
  ('REQ-2026-2030', 'neighborhood_amenity', 'neighborhood_amenity_lookup', 'da_xac_thuc', 'Tiện ích xung quanh', ARRAY['Trường tiểu học: 287m · Chợ dân sinh: 441m','Trạm xe bus: 275m · Bệnh viện quận: 1.3km'], 'Mật độ tiện ích cao hơn trung bình khu vực — yếu tố hỗ trợ tích cực cho nhu cầu ở thực và thanh khoản khi cần bán lại.', 'neighborhood_amenity_lookup', 95),
  ('REQ-2026-2030', 'environmental_risk', 'environmental_risk_lookup', 'da_xac_thuc', 'Môi trường', ARRAY['Không ghi nhận ngập úng trong 3 năm gần nhất.','Không nằm trong vùng cảnh báo sạt lở, ô nhiễm công nghiệp.'], 'Rủi ro môi trường ở mức thấp, không ảnh hưởng đáng kể đến giá trị định giá.', 'environmental_risk_lookup', 93),
  ('REQ-2026-2030', 'liquidity_stat', 'liquidity_stat_lookup', 'luu_y', 'Thanh khoản khu vực', ARRAY['Thời gian bán trung bình: 113 ngày · Tỷ lệ giao dịch thành công: 56%','Số tin rao bán cùng phân khúc trong bán kính 1km: 4 tin'], 'Thanh khoản thấp hơn mặt bằng chung khu vực — cần cân nhắc thêm khi xác định LTV để đảm bảo khả năng xử lý tài sản bảo đảm.', 'liquidity_stat_lookup', 47),
  ('REQ-2026-2030', 'stigma_reputation', 'stigma_reputation_lookup', 'da_xac_thuc', 'Dư luận / tâm linh', ARRAY['Không ghi nhận tin đồn hay sự việc bất thường liên quan tài sản/khu vực.','Không có bài báo, hồ sơ công an hoặc dữ liệu tiêu cực liên quan.'], 'Không phát hiện yếu tố bất lợi về dư luận/tâm linh — không ảnh hưởng đến giá trị hay thanh khoản.', 'stigma_reputation_lookup', 84),
