  ('REQ-2026-2057', 'environmental_risk', 'environmental_risk_lookup', 'da_xac_thuc', 'Môi trường', ARRAY['Không ghi nhận ngập úng trong 3 năm gần nhất.','Không nằm trong vùng cảnh báo sạt lở, ô nhiễm công nghiệp.'], 'Rủi ro môi trường ở mức thấp, không ảnh hưởng đáng kể đến giá trị định giá.', 'environmental_risk_lookup', 86),
  ('REQ-2026-2057', 'liquidity_stat', 'liquidity_stat_lookup', 'da_xac_thuc', 'Thanh khoản khu vực', ARRAY['Thời gian bán trung bình: 27 ngày · Tỷ lệ giao dịch thành công: 83%','Số tin rao bán cùng phân khúc trong bán kính 1km: 18 tin'], 'Thanh khoản khá tốt so với mặt bằng chung phân khúc — hỗ trợ tích cực cho khả năng xử lý tài sản bảo đảm khi cần thiết.', 'liquidity_stat_lookup', 91),
  ('REQ-2026-2057', 'stigma_reputation', 'stigma_reputation_lookup', 'da_xac_thuc', 'Dư luận / tâm linh', ARRAY['Không ghi nhận tin đồn hay sự việc bất thường liên quan tài sản/khu vực.','Không có bài báo, hồ sơ công an hoặc dữ liệu tiêu cực liên quan.'], 'Không phát hiện yếu tố bất lợi về dư luận/tâm linh — không ảnh hưởng đến giá trị hay thanh khoản.', 'stigma_reputation_lookup', 86),
  ('REQ-2026-2058', 'market_price', 'market_price_lookup', 'da_xac_thuc', 'Giá thị trường', ARRAY['7 giao dịch so sánh trong bán kính 1.7km.'], 'Giá giao dịch so sánh dao động 69.2–93.2 triệu/m², trung vị khoảng 82.5 triệu/m². Giá tương đối ổn định qua các giao dịch gần đây, chưa thấy biến động bất thường. Nên ưu tiên trọng số cao hơn cho các giao dịch gần đây khi đưa vào bước định giá.', 'market_price_lookup', 81),
  ('REQ-2026-2058', 'planning_zoning', 'planning_zoning_lookup', 'da_xac_thuc', 'Quy hoạch', ARRAY['Không nằm trong khu vực quy hoạch treo.','Lộ giới hẻm/đường dự kiến giữ nguyên theo đồ án quy hoạch 1/2000 phê duyệt 2024.','Không thuộc diện giải toả, thu hồi đất.'], 'Không có yếu tố quy hoạch bất lợi, có thể tăng nhẹ giá trị nếu lộ giới được mở rộng trong 2–3 năm tới nhờ cải thiện khả năng tiếp cận.', 'planning_zoning_lookup', 91),
  ('REQ-2026-2058', 'legal_status', 'legal_status_lookup', 'da_xac_thuc', 'Pháp lý', ARRAY['Sổ hồng đứng tên chính chủ, cấp 21/07/2018.','Không ghi nhận tranh chấp, kê biên hay khiếu nại.','Không đang thế chấp tại tổ chức tín dụng khác.'], 'Tình trạng pháp lý sạch, đủ điều kiện nhận thế chấp. Yếu tố tích cực, giảm đáng kể rủi ro khi xử lý tài sản bảo đảm nếu phát sinh nợ xấu.', 'legal_status_lookup', 87),
  ('REQ-2026-2058', 'neighborhood_amenity', 'neighborhood_amenity_lookup', 'da_xac_thuc', 'Tiện ích xung quanh', ARRAY['Trường tiểu học: 167m · Chợ dân sinh: 671m','Trạm xe bus: 285m · Bệnh viện quận: 1.8km'], 'Mật độ tiện ích cao hơn trung bình khu vực — yếu tố hỗ trợ tích cực cho nhu cầu ở thực và thanh khoản khi cần bán lại.', 'neighborhood_amenity_lookup', 80),
  ('REQ-2026-2058', 'environmental_risk', 'environmental_risk_lookup', 'da_xac_thuc', 'Môi trường', ARRAY['Không ghi nhận ngập úng trong 3 năm gần nhất.','Không nằm trong vùng cảnh báo sạt lở, ô nhiễm công nghiệp.'], 'Rủi ro môi trường ở mức thấp, không ảnh hưởng đáng kể đến giá trị định giá.', 'environmental_risk_lookup', 84),
  ('REQ-2026-2058', 'liquidity_stat', 'liquidity_stat_lookup', 'da_xac_thuc', 'Thanh khoản khu vực', ARRAY['Thời gian bán trung bình: 39 ngày · Tỷ lệ giao dịch thành công: 79%','Số tin rao bán cùng phân khúc trong bán kính 1km: 12 tin'], 'Thanh khoản khá tốt so với mặt bằng chung phân khúc — hỗ trợ tích cực cho khả năng xử lý tài sản bảo đảm khi cần thiết.', 'liquidity_stat_lookup', 87),
  ('REQ-2026-2058', 'stigma_reputation', 'stigma_reputation_lookup', 'da_xac_thuc', 'Dư luận / tâm linh', ARRAY['Không ghi nhận tin đồn hay sự việc bất thường liên quan tài sản/khu vực.','Không có bài báo, hồ sơ công an hoặc dữ liệu tiêu cực liên quan.'], 'Không phát hiện yếu tố bất lợi về dư luận/tâm linh — không ảnh hưởng đến giá trị hay thanh khoản.', 'stigma_reputation_lookup', 85),
  ('REQ-2026-2059', 'market_price', 'market_price_lookup', 'da_xac_thuc', 'Giá thị trường', ARRAY['7 giao dịch so sánh trong bán kính 1.1km.'], 'Giá giao dịch so sánh dao động 573.2–797.9 triệu/m², trung vị khoảng 635.1 triệu/m². Xu hướng tăng theo thời gian, giao dịch gần nhất cao hơn đáng kể so với giao dịch xa nhất, cho thấy khu vực đang trong đà tăng giá. Nên ưu tiên trọng số cao hơn cho các giao dịch gần đây khi đưa vào bước định giá.', 'market_price_lookup', 81),
  ('REQ-2026-2059', 'planning_zoning', 'planning_zoning_lookup', 'da_xac_thuc', 'Quy hoạch', ARRAY['Không nằm trong khu vực quy hoạch treo.','Lộ giới hẻm/đường dự kiến giữ nguyên theo đồ án quy hoạch 1/2000 phê duyệt 2021.','Không thuộc diện giải toả, thu hồi đất.'], 'Không có yếu tố quy hoạch bất lợi, có thể tăng nhẹ giá trị nếu lộ giới được mở rộng trong 2–3 năm tới nhờ cải thiện khả năng tiếp cận.', 'planning_zoning_lookup', 87),
  ('REQ-2026-2059', 'legal_status', 'legal_status_lookup', 'luu_y', 'Pháp lý', ARRAY['Sổ hồng đứng tên chính chủ nhưng có ghi chú thế chấp đã tất toán, chưa xoá đăng ký.','Không ghi nhận tranh chấp tại thời điểm tra cứu.'], 'Cần yêu cầu khách hàng bổ sung văn bản xoá đăng ký thế chấp cũ trước khi hoàn tất hồ sơ.', 'legal_status_lookup', 55),
  ('REQ-2026-2059', 'neighborhood_amenity', 'neighborhood_amenity_lookup', 'da_xac_thuc', 'Tiện ích xung quanh', ARRAY['Trường tiểu học: 179m · Chợ dân sinh: 699m','Trạm xe bus: 282m · Bệnh viện quận: 2.3km'], 'Mật độ tiện ích cao hơn trung bình khu vực — yếu tố hỗ trợ tích cực cho nhu cầu ở thực và thanh khoản khi cần bán lại.', 'neighborhood_amenity_lookup', 83),
  ('REQ-2026-2059', 'environmental_risk', 'environmental_risk_lookup', 'da_xac_thuc', 'Môi trường', ARRAY['Không ghi nhận ngập úng trong 3 năm gần nhất.','Không nằm trong vùng cảnh báo sạt lở, ô nhiễm công nghiệp.'], 'Rủi ro môi trường ở mức thấp, không ảnh hưởng đáng kể đến giá trị định giá.', 'environmental_risk_lookup', 92),
  ('REQ-2026-2059', 'liquidity_stat', 'liquidity_stat_lookup', 'luu_y', 'Thanh khoản khu vực', ARRAY['Thời gian bán trung bình: 146 ngày · Tỷ lệ giao dịch thành công: 49%','Số tin rao bán cùng phân khúc trong bán kính 1km: 1 tin'], 'Thanh khoản thấp hơn mặt bằng chung khu vực — cần cân nhắc thêm khi xác định LTV để đảm bảo khả năng xử lý tài sản bảo đảm.', 'liquidity_stat_lookup', 37),
  ('REQ-2026-2059', 'stigma_reputation', 'stigma_reputation_lookup', 'chua_xac_thuc', 'Dư luận / tâm linh', ARRAY['Ghi nhận tin đồn dân cư chưa xác thực liên quan 1 sự việc năm 2019.','Không có bài báo, hồ sơ công an hoặc dữ liệu chính thức xác nhận.'], 'Độ tin cậy nguồn tin thấp, chưa đủ cơ sở kết luận ảnh hưởng đến giá trị hay thanh khoản. Khuyến nghị thẩm định viên xác minh thực địa trước khi đưa vào báo cáo chính thức.', 'stigma_reputation_lookup', 45);
